def get_ai_response(question: str, lang: str = 'ru') -> str:
    """Smart rule-based AI with extensive flower knowledge."""

    # Try OpenAI if key available
    if OPENAI_API_KEY:
        try:
            import urllib.request, json as _json
            data = _json.dumps({
                'model': 'gpt-3.5-turbo',
                'messages': [
                    {'role': 'system', 'content': 'Ты Flora — дружелюбный AI-помощник цветочного магазина Flora Luxe в Ташкенте. Отвечай кратко, мило, с эмодзи. Язык: ' + lang},
                    {'role': 'user', 'content': question}
                ],
                'max_tokens': 250,
                'temperature': 0.7
            }).encode('utf-8')
            req = urllib.request.Request(
                'https://api.openai.com/v1/chat/completions',
                data=data,
                headers={
                    'Authorization': f'Bearer {OPENAI_API_KEY}',
                    'Content-Type': 'application/json'
                }
            )
            with urllib.request.urlopen(req, timeout=10) as resp:
                result = _json.loads(resp.read())
                return result['choices'][0]['message']['content']
        except Exception:
            pass  # Fallback to local knowledge

    # Local knowledge lookup
    q = question.lower().strip()
    answers = FLOWER_KNOWLEDGE.get(lang, FLOWER_KNOWLEDGE['ru'])

    # Exact key match first
    for keyword, answer in answers.items():
        if keyword != 'default' and keyword == q:
            return answer

    # Substring match (longest key wins)
    best_match = None
    best_len = 0
    for keyword, answer in answers.items():
        if keyword == 'default':
            continue
        if keyword in q and len(keyword) > best_len:
            best_match = answer
            best_len = len(keyword)

    if best_match:
        return best_match

    # Cross-language fallback: try all languages
    for try_lang in ('ru', 'en', 'uz'):
        if try_lang == lang:
            continue
        alt = FLOWER_KNOWLEDGE.get(try_lang, {})
        for keyword, answer in alt.items():
            if keyword != 'default' and keyword in q:
                # Translate the answer hint
                if lang == 'ru':
                    return FLOWER_KNOWLEDGE['ru'].get('default', '')
                elif lang == 'uz':
                    return FLOWER_KNOWLEDGE['uz'].get('default', '')
                else:
                    return FLOWER_KNOWLEDGE['en'].get('default', '')

    return answers.get('default', FLOWER_KNOWLEDGE['ru']['default'])
